REQUIRED = ['wheel','worktree','branch','focus','progress_file']
import json
def validate(raw):
    a = raw
    if isinstance(a, str):
        try: a = json.loads(a)
        except Exception as e: return (False, list(REQUIRED), f"non-JSON string")
    if a is None or not isinstance(a, dict):
        return (False, list(REQUIRED), f"args is {'null' if a is None else type(a).__name__}")
    missing=[]
    for k in REQUIRED:
        v = a.get(k)
        # JS: typeof v !== 'string' || v.trim()==='' || v==='undefined' || v==='null'
        if not isinstance(v,str) or v.strip()=='' or v=='undefined' or v=='null':
            missing.append(k)
    return (len(missing)==0, missing, None)

cases = {
 "undefined(None)": None,
 "empty {}": {},
 "all-'undefined'": {k:'undefined' for k in REQUIRED},
 "partial (missing branch,focus,pf)": {'wheel':'x','worktree':'/tmp'},
 "empty-string worktree": {'wheel':'x','worktree':'  ','branch':'b','focus':'f','progress_file':'p'},
 "non-JSON string": "not json {",
 "valid": {k:('/tmp' if k=='worktree' else k) for k in REQUIRED},
 "'null' literal": {**{k:k for k in REQUIRED}, 'branch':'null'},
}
for name,c in cases.items():
    ok,missing,reason = validate(c)
    print(f"{name:35s} ok={ok!s:5s} missing={missing} reason={reason}")
PY
